// GET /api/admin/publishers
exports.getAll = async (req, res, next) => {
  try {
    const { page = 1, limit = 20, search, status } = req.query;
    const offset = (page - 1) * limit;

    let query = `SELECT * FROM publishers WHERE 1=1`;
    const params = [];
    let paramIndex = 1;

    if (search) {
      query += ` AND (slug ILIKE $${paramIndex} OR name::text ILIKE $${paramIndex})`;
      params.push(`%${search}%`);
      paramIndex++;
    }

    if (status && status !== 'undefined') {
      query += ` AND status = $${paramIndex}`;
      params.push(status);
      paramIndex++;
    }

    query += ` ORDER BY created_at DESC LIMIT $${paramIndex} OFFSET $${paramIndex + 1}`;
    params.push(parseInt(limit), offset);

    const { rows } = await pool.query(query, params);

    // Get total count with same filters
    let countQuery = 'SELECT COUNT(*) as total FROM publishers WHERE 1=1';
    const countParams = [];
    let countParamIndex = 1;

    if (search) {
      countQuery += ` AND (slug ILIKE $${countParamIndex} OR name::text ILIKE $${countParamIndex})`;
      countParams.push(`%${search}%`);
      countParamIndex++;
    }

    if (status && status !== 'undefined') {
      countQuery += ` AND status = $${countParamIndex}`;
      countParams.push(status);
      countParamIndex++;
    }

    const { rows: countRows } = await pool.query(countQuery, countParams);

    return res.json({
      success: true,
      data: rows,
      pagination: {
        page: parseInt(page),
        limit: parseInt(limit),
        total: parseInt(countRows[0].total),
        totalPages: Math.ceil(countRows[0].total / limit),
      },
    });
  } catch (error) {
    return next(error);
  }
};

// GET /api/admin/publishers/:id
exports.getById = async (req, res, next) => {
  try {
    const { id } = req.params;
    const { rows } = await pool.query('SELECT * FROM publishers WHERE id = $1', [id]);

    if (rows.length === 0) {
      return res.status(404).json({
        success: false,
        message: 'Không tìm thấy publisher',
      });
    }

    return res.json({
      success: true,
      data: rows[0],
    });
  } catch (error) {
    return next(error);
  }
};

// POST /api/admin/publishers
exports.create = async (req, res, next) => {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');

    const { 
      name, 
      slug, 
      description, 
      address, 
      phone, 
      email, 
      website, 
      status 
    } = req.body;

    const nameJson = typeof name === 'object' ? name : { vi: name };
    const descJson = typeof description === 'object' ? description : { vi: description || "" };

    const query = `
      INSERT INTO publishers (
        name, slug, description, address, phone, email, website, status
      ) VALUES ($1, $2, $3, $4, $5, $6, $7, $8) RETURNING *
    `;
    const params = [
      JSON.stringify(nameJson),
      slug,
      JSON.stringify(descJson),
      address || null,
      phone || null,
      email || null,
      website || null,
      status || 'active'
    ];

    const { rows } = await client.query(query, params);

    await client.query('COMMIT');

    return res.status(201).json({
      success: true,
      message: 'Đã tạo publisher thành công',
      data: rows[0],
    });
  } catch (error) {
    await client.query('ROLLBACK');
    return next(error);
  } finally {
    client.release();
  }
};

// PUT /api/admin/publishers/:id
exports.update = async (req, res, next) => {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');

    const { id } = req.params;
    const data = req.body;

    // Check if exists
    const { rows: existing } = await client.query('SELECT * FROM publishers WHERE id = $1', [id]);
    if (existing.length === 0) {
      await client.query('ROLLBACK');
      return res.status(404).json({
        success: false,
        message: 'Không tìm thấy publisher',
      });
    }

    // Build update query
    const updateFields = [];
    const params = [];
    let paramIndex = 1;

    const fieldsToHandle = ['slug', 'address', 'phone', 'email', 'website', 'logo_url', 'status'];
    
    // Xử lý name (JSONB)
    if (data.name !== undefined) {
      updateFields.push(`name = $${paramIndex++}`);
      params.push(JSON.stringify(typeof data.name === 'object' ? data.name : { vi: data.name }));
    }

    // Xử lý description (JSONB)
    if (data.description !== undefined) {
      updateFields.push(`description = $${paramIndex++}`);
      params.push(JSON.stringify(typeof data.description === 'object' ? data.description : { vi: data.description || "" }));
    }

    // Xử lý các trường thông thường
    fieldsToHandle.forEach(field => {
      if (data[field] !== undefined) {
        updateFields.push(`${field} = $${paramIndex++}`);
        params.push(data[field]);
      }
    });

    if (updateFields.length > 0) {
      params.push(id);
      await client.query(
        `UPDATE publishers SET ${updateFields.join(', ')} WHERE id = $${paramIndex}`,
        params
      );
    }

    await client.query('COMMIT');

    const { rows } = await client.query('SELECT * FROM publishers WHERE id = $1', [id]);

    return res.json({
      success: true,
      message: 'Đã cập nhật publisher thành công',
      data: rows[0],
    });
  } catch (error) {
    await client.query('ROLLBACK');
    return next(error);
  } finally {
    client.release();
  }
};

// DELETE /api/admin/publishers/:id
exports.remove = async (req, res, next) => {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');

    const { id } = req.params;

    const { rows } = await client.query('SELECT * FROM publishers WHERE id = $1', [id]);
    if (rows.length === 0) {
      await client.query('ROLLBACK');
      return res.status(404).json({
        success: false,
        message: 'Không tìm thấy publisher',
      });
    }

    await client.query('DELETE FROM publishers WHERE id = $1', [id]);

    await client.query('COMMIT');

    return res.json({
      success: true,
      message: 'Đã xóa publisher thành công',
    });
  } catch (error) {
    await client.query('ROLLBACK');
    return next(error);
  } finally {
    client.release();
  }
};
